// Serper.dev returns clean JSON — no scraping needed!
const raw = $input.first().json;
// Serper response may be in .data (string) or direct object
let d = raw;
if (typeof raw.data === 'string') { try { d = JSON.parse(raw.data); } catch(e) {} }
else if (raw.data && typeof raw.data === 'object') d = raw.data;

// Detect Serper errors (missing/invalid API key, quota, etc.)
let errMsg = '';
if (d && d.message && !d.organic) errMsg = 'Serper error: ' + d.message;
if (d && d.statusCode && d.statusCode >= 400) errMsg = 'Serper HTTP ' + d.statusCode + ': ' + (d.message || 'check API key');

const organic = d.organic || [];
const peopleAlsoAsk = d.peopleAlsoAsk || [];
const relatedSearches = d.relatedSearches || [];

const competitors = organic.slice(0, 10).map((r, i) => ({
  position: r.position || (i + 1),
  url: r.link || '',
  domain: (function(){ try { return new URL(r.link).hostname.replace(/^www\./,''); } catch(e){ return ''; } })(),
  title: r.title || '',
  snippet: r.snippet || '',
  word_count: (r.snippet || '').split(/\s+/).length,
  h1_count: 0, h2_count: 0, h3_count: 0, images: 0, schema_types: '',
  top_keywords: [], headings: {h1:[],h2:[],h3:[]}
}));

// Questions from People Also Ask
const questions = peopleAlsoAsk.map(p => p.question || p).filter(Boolean).slice(0, 10);

// LSI from related searches
const lsi = relatedSearches.map(r => r.query || r).filter(Boolean).slice(0, 20);

// Content gap: extract common words from titles
const titleWords = {};
competitors.forEach(c => {
  (c.title.match(/[\u0600-\u06FF\u200C]{3,}/g) || []).forEach(w => {
    titleWords[w] = (titleWords[w] || 0) + 1;
  });
});
const gap = Object.entries(titleWords).filter(e => e[1] >= 2).sort((a,b)=>b[1]-a[1]).slice(0,15).map(e=>e[0]);

const avgW = competitors.length ? Math.round(competitors.reduce((s,c)=>s+c.word_count,0)/competitors.length) : 0;
const dbg = errMsg ? errMsg : ('organic:' + organic.length + ' paa:' + peopleAlsoAsk.length + ' related:' + relatedSearches.length);

return [{json: {
  analysis_id: $node.Webhook.json.body.analysis_id || '',
  callback_url: $node.Webhook.json.body.callback_url || '',
  avg_word_count: avgW,
  avg_headings: 0,
  lsi_keywords: lsi,
  content_gap: gap,
  questions: questions,
  competitors: competitors,
  error: errMsg,
  debug: dbg
}}];
